import org.owasp.encoder.Encode;

import java.io.IOException;
import java.io.PrintWriter;

public class XSSSecureCode {
    public static void main(String[] args) throws IOException {
        // Simulating user input (could come from a form submission)
        String userInput = "<script>alert('XSS attack!')</script>";

        // Properly handling user input with HTML escaping
        PrintWriter out = new PrintWriter("output.html");
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Welcome, " + Encode.forHtml(userInput) + "</h1>"); // Escaping user input
        out.println("</body>");
        out.println("</html>");

        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
